2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // ===== Quote: empty and processing fee =====
7	  it("empty item list yields premium of 5 G (processing fee only)", () => {
8	    expect(quote({ customer: { yearsWithMHPCO: 0, previousContracts: 0 }, items: [] })).toBe(5);
9	  });
10	
11	  // ===== Quote: single item base premiums (no modifiers, follow-up contract to neutralize first-insurance) =====
12	  // Use a long-standing customer's follow-up contract OR show base via integration.
13	  // We start with the simplest: single-item premiums combining base + first-insurance for a newcomer with no history.
14	  it("newcomer single sword (steel, enchantment 0, not cursed) yields premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
15	    expect(
16	      quote({
17	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
18	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
19	      })
20	    ).toBe(115);
21	  });
22	  it("newcomer single amulet yields premium 71 G (60 base + 6 first-insurance + 5 fee)", () => {
23	    expect(
24	      quote({
25	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
26	        items: [{ type: "amulet" }],
27	      })
28	    ).toBe(71);
29	  });
30	  it("newcomer single staff yields premium 93 G (80 base + 8 first-insurance + 5 fee)", () => {
31	    expect(
32	      quote({
33	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
34	        items: [{ type: "staff" }],
35	      })
36	    ).toBe(93);
37	  });
38	  it("newcomer single potion yields premium 49 G (40 base + 4 first-insurance + 5 fee)", () => {
39	    expect(
40	      quote({
41	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
42	        items: [{ type: "potion" }],
43	      })
44	    ).toBe(49);
45	  });
46	  it("newcomer single rune yields premium 33 G (25 base + 3 first-insurance + 5 fee, rounded up)", () => {
47	    expect(
48	      quote({
49	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
50	        items: [{ type: "rune" }],
51	      })
52	    ).toBe(33);
53	  });
54	
55	  // ===== Quote: component blocks =====
56	  it("2 runes yield base premium 50 G (no block applies)", () => {
57	    expect(
58	      quote({
59	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
60	        items: [{ type: "rune" }, { type: "rune" }],
61	      })
62	    ).toBe(60);
63	  });
64	  it("3 runes yield base premium 60 G (block of 3 alike applies)", () => {
65	    expect(
66	      quote({
67	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
68	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
69	      })
70	    ).toBe(71);
71	  });
72	  it("4 runes yield base premium 100 G (block requires exactly 3)", () => {
73	    expect(
74	      quote({
75	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
76	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
77	      })
78	    ).toBe(115);
79	  });
80	  it("7 runes yield base premium 175 G (no block)", () => {
81	    expect(
82	      quote({
83	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
84	        items: [
85	          { type: "rune" },
86	          { type: "rune" },
87	          { type: "rune" },
88	          { type: "rune" },
89	          { type: "rune" },
90	          { type: "rune" },
91	          { type: "rune" },
92	        ],
93	      })
94	    ).toBe(198);
95	  });
96	  it("2 runes + 1 moonstone yield base premium 75 G (different types, no block)", () => {
97	    expect(
98	      quote({
99	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
100	        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
101	      })
102	    ).toBe(88);
103	  });
104	  it("3 runes + 3 moonstones yield base premium 120 G (two separate blocks)", () => {
105	    expect(
106	      quote({
107	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
108	        items: [
109	          { type: "rune" },
110	          { type: "rune" },
111	          { type: "rune" },
112	          { type: "moonstone" },
113	          { type: "moonstone" },
114	          { type: "moonstone" },
115	        ],
116	      })
117	    ).toBe(137);
118	  });
119	
120	  // ===== Quote: item-specific modifiers =====
121	  it("cursed sword adds 50% surcharge on item base (cursed sword alone: 100 + 50 = 150 base)", () => {
122	    expect(
123	      quote({
124	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
125	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
126	      })
127	    ).toBe(170);
128	  });
129	  it("highly enchanted sword (enchantment 5) adds 30% surcharge on item base", () => {
130	    expect(
131	      quote({
132	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
133	        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
134	      })
135	    ).toBe(148);
136	  });
137	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
138	  it.todo("cursed sword with enchantment 5 stacks both surcharges on item base");
139	
140	  // ===== Quote: modifier scope on multi-item policies =====
141	  it.todo("policy with cursed sword + plain amulet: cursed surcharge applies only to cursed item base (newcomer total 231 G)");
142	
143	  // ===== Quote: policy-wide modifiers =====
144	  it.todo("long-standing customer (exactly 2 years) receives 20% loyalty discount on policy base");
145	  it.todo("first insurance (newcomer, no prior contracts) adds 10% surcharge on policy base");
146	  it.todo("follow-up contract gives 15% discount on policy base");
147	
148	  // ===== Quote: rounding in MHPCO's favor =====
149	  it.todo("premium calculation that yields 197.5 G rounds up to 198 G");
150	  it.todo("intermediate amounts kept as fractions; only final premium is rounded");
151	
152	  // ===== Quote: integration examples from spec =====
153	  it.todo("newcomer with cursed sword (steel, enchantment 3) yields premium 165 G");
154	  it.todo("long-standing (3 yrs) customer's second quote with cursed sword (enchantment 7) yields premium 160 G");
155	
156	  // ===== Claim: basic deductible =====
157	  it.todo("regular sword (steel, enchantment 3), damage 500 G yields payout 400 G (full minus 100 deductible)");
158	  it.todo("rune (insurance value 250 G), damage 200 G yields payout 100 G (full minus deductible, no special clauses)");
159	
160	  // ===== Claim: special clauses =====
161	  it.todo("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)");
162	  it.todo("dragon-material sword enchantment 5, damage 800 G yields payout 700 G (full minus deductible)");
163	  it.todo("dragon-material sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible — both clauses apply)");
164	  it.todo("dragon-material sword exactly enchantment 8, damage 1000 G yields payout 400 G (50% then deductible)");
165	
166	  // ===== Claim: deductible per damage event (multi-item incident) =====
167	  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout 600 G (deductible per item)");
168	
169	  // ===== Claim: rounding =====
170	  it.todo("payout calculation that yields 350.5 G rounds down to 350 G");
171	
172	  // ===== Claim: insurance sum and cap =====
173	  it.todo("policy of sword + amulet: insurance sum 1600 G, cap 3200 G");
174	  it.todo("policy of sword + 3 runes (a block): insurance sum 1750 G (block discount affects premium only)");
175	  it.todo("cursed sword: cap 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");
176	
177	  // ===== Claim: cap exhaustion across successive claims =====
178	  it.todo("sword (cap 2000 G), first claim 1500 G yields payout 1400 G, remainingCap 600 G");
179	  it.todo("sword (cap 2000 G), after first 1500 G claim, second 1500 G claim yields payout 600 G, remainingCap 0 G");
180	
181	  // ===== Claim: multiple items of same type =====
182	  it.todo("policy covers two swords: insurance sum 2000 G, cap 4000 G");
183	  it.todo("dragon attack damages both insured swords: each entry treated separately with own deductible");
184	
185	  // ===== CLI / scenario integration =====
186	  it.todo("scenario with quote then claim returns results array of length 2 with {premium} and {payout, remainingCap}");
187	
188	  // ===== Error cases =====
189	  it.todo("quote with unknown item type (e.g. broomstick) causes CLI to exit non-zero with stderr error");
190	  it.todo("claim referencing damage to an item not in the policy causes CLI to exit non-zero with stderr error");
191	  it.todo("claim with damages array containing more entries of a type than insured causes CLI to exit non-zero");
192	  it.todo("claim with negative damage amount causes CLI to exit non-zero with stderr error");
193	});
