2	
3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const CURSED_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const COMPONENT_BASE = 25;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	
28	const ITEM_BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	function isComponentType(type: string): boolean {
38	  return ITEM_BASE_PREMIUMS[type] === COMPONENT_BASE;
39	}
40	
41	function groupItemsByType(items: Item[]): Map<string, Item[]> {
42	  const groups = new Map<string, Item[]>();
43	  for (const item of items) {
44	    const group = groups.get(item.type) ?? [];
45	    group.push(item);
46	    groups.set(item.type, group);
47	  }
48	  return groups;
49	}
50	
51	function totalSurchargeRate(item: Item): number {
52	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
53	  const highEnchantmentRate =
54	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
55	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
56	      : 0;
57	  return cursedRate + highEnchantmentRate;
58	}
59	
60	function calculateItemBase(type: string, item: Item): number {
61	  const base = ITEM_BASE_PREMIUMS[type];
62	  return base * (1 + totalSurchargeRate(item));
63	}
64	
65	function calculateGroupBase(type: string, group: Item[]): number {
66	  if (isComponentType(type) && group.length === 3) {
67	    return COMPONENT_BLOCK_PREMIUM;
68	  }
69	  return group.reduce((sum, item) => sum + calculateItemBase(type, item), 0);
70	}
71	
72	function calculatePolicyBase(items: Item[]): number {
73	  const groups = groupItemsByType(items);
74	  return Array.from(groups).reduce(
75	    (total, [type, group]) => total + calculateGroupBase(type, group),
76	    0
77	  );
78	}
79	
80	export function quote(input: QuoteInput): number {
81	  const policyBase = calculatePolicyBase(input.items);
82	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
83	  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
84	}
